export default {
    generate(builder, project, config) {
        project.useProject('@user1/lib3_p')
        const lib2 = project.createTarget('lib2')
        lib2.LIBRARY = true
        lib2.addSource('lib2.c')
        lib2.addDependency('lib3')
        lib2.addExportIncludeDirectory('.')
    }
}
